```js
let montant;
do {
    montant = parseInt(prompt('Entrez un montant multiple de 1000 FCFA :'));
} while(isNaN(montant) || montant <= 0 || montant % 1000 !== 0);

let billets = [5000, 2000, 1000];
let resultat = '';
let reste = montant;
for(let i = 0; i < billets.length; i++) {
    let nb = Math.floor(reste / billets[i]);
    if(nb > 0) {
        resultat += `${nb} x ${billets[i]} FCFA\n`;
        reste -= nb * billets[i];
    }
}
console.log(`Pour ${montant} FCFA :\n${resultat}`);
```
